"use strict";const e=require("../utils/request.js");const t={getVenueList:function(t){return e.get("/venues",t,{cache:!1})},getVenueDetail:function(t){return e.get(`/venues/${t}`)},getVenueTimeSlots:function(t,n,u={}){return e.get(`/timeslots/venue/${t}/date/${n}`,u)},getVenueTypes:function(){return e.get("/venues/types")},getPopularVenues:function(t=5){return e.get("/venues/popular",{limit:t},{cache:!1})},searchVenues:function(t){return e.get("/venues/search",t)},getSharingVenues:function(t){return e.get("/venues/sharing",t)}};exports.venueApi=t;
